var binaryGap = function(n) {
    let last = -1, best = 0, i = 0;
    while (n > 0) {
        if (n & 1) {
            if (last >= 0) best = Math.max(best, i - last);
            last = i;
        }
        n = Math.floor(n / 2);
        i++;
    }
    return best;
};
